export type RegulationMatch = {
  zone: RegulationZone;
  exact: boolean;
  distanceMeters: number;
};

const NEARBY_THRESHOLD_METERS = 35;

/**
 * Finds the on-street parking regulation applying at a given point.
 * Prefers an exact (inside-polygon) match over the nearest one, and
 * prefers a non-event regulation over an overlapping "evenement" one
 * so the everyday rule is shown unless only an event zone matches.
 */
export function findRegulationZone(point: LatLng): RegulationMatch | null {
  const exactMatches = REGULATION_ZONES.filter((z) => isPointInAnyPolygon(point, z.polygons));
  if (exactMatches.length > 0) {
    const nonEvent = exactMatches.find((z) => z.type !== "evenement");
    return { zone: nonEvent ?? exactMatches[0], exact: true, distanceMeters: 0 };
  }

  let best: RegulationMatch | null = null;
  for (const zone of REGULATION_ZONES) {
    const d = distanceToAnyPolygon(point, zone.polygons);
    if (d <= NEARBY_THRESHOLD_METERS && (!best || d < best.distanceMeters)) {
      best = { zone, exact: false, distanceMeters: d };
    }
  }
  return best;
}
